    public:
        static SistemaDeArchivo * getInstance();
        ~SistemaDeArchivo();
        void crearArchivo(int idDir, int idArch, int tam);
        int calcularTamanoElemento(int id);
    private:
        static SistemaDeArchivo * instancia;
        IDictionary * elementos;
        SistemaDeArchivo();
