class Elemento: public ICollectible {
    public:
        Elemento(int id);
        ~Elemento();
        virtual int calcularTamano() = 0;
    private:
        int id;
};
class Archivo: public Elemento {
    public:
        Archivo(int id, int tam);
        int calcularTamano();
    private:
        int tamano;
};

class Directorio : public Elemento {
    public:
        Directorio(int id);
        ~Directorio();
        int calcularTamano();
        Archivo * crearArchivo(int idArch, int tam);
    private:
