void Subject::notifyObservers(Event * ev){ 
    IIterator * it = this->observers->getIterator(); 
    Observer * o; 
    while (it->hasCurrent()) { 
        o = (Observer *) it->current(); 
        o->notify(ev); 
        if(ev->isCancelled()){ 
            this->onCancel(o); 
            break; 
        } 
        it->next(); 
    } 
    delete it; 
} 
